<?php
require_once __DIR__ . '/../includes/membership.php';
require_once __DIR__ . '/../includes/media_delivery.php';
require_once __DIR__ . '/../includes/revenue_access_governance.php';
sf_revenue_guard_json_write('playlist',120,900);$member=sf_member_snapshot();$userId=sf_current_user_id();if(!$userId)sf_json_response(['ok'=>false,'error'=>'login_required'],401);if(empty($member['can_manage_playlists']))sf_json_response(['ok'=>false,'error'=>'subscription_required'],403);$pdo=sf_db();if(!$pdo)sf_json_response(['ok'=>false,'error'=>'database_not_configured'],503);$data=sf_request_json();$action=(string)($data['action']??'create');$limits=sf_revenue_playlist_limits($member);
function sf_playlist_slug(string $title): string{return strtolower(trim(preg_replace('/[^a-z0-9]+/i','-',$title),'-')).'-'.substr(bin2hex(random_bytes(3)),0,6);}
function sf_member_default_playlist(PDO $pdo,int $userId,int $limit): int{$lock='sf_playlist_default_'.substr(hash('sha256',(string)$userId),0,32);$locked=false;try{$stmt=$pdo->prepare('SELECT GET_LOCK(?,2)');$stmt->execute([$lock]);$locked=(int)$stmt->fetchColumn()===1;$find=$pdo->prepare('SELECT id FROM playlists WHERE user_id=? ORDER BY id LIMIT 1');$find->execute([$userId]);$id=(int)$find->fetchColumn();if($id>0)return$id;$count=$pdo->prepare('SELECT COUNT(*) FROM playlists WHERE user_id=?');$count->execute([$userId]);if((int)$count->fetchColumn()>=$limit)throw new RuntimeException('playlist_limit_reached');$title='My Road Songs';$stmt=$pdo->prepare("INSERT INTO playlists (user_id,title,slug,description,visibility) VALUES (?,?,?,?,'private')");$stmt->execute([$userId,$title,sf_playlist_slug($title),'Auto-created member playlist for saved Stonefellow songs.']);return(int)$pdo->lastInsertId();}finally{if($locked){try{$release=$pdo->prepare('SELECT RELEASE_LOCK(?)');$release->execute([$lock]);}catch(Throwable$ignore){}}}}
try{if($action==='create'){$title=trim((string)($data['title']??''));$description=trim((string)($data['description']??''));if($title===''||strlen($title)>120)sf_json_response(['ok'=>false,'error'=>'invalid_title'],422);if(strlen($description)>1000)sf_json_response(['ok'=>false,'error'=>'description_too_long'],422);$count=$pdo->prepare('SELECT COUNT(*) FROM playlists WHERE user_id=?');$count->execute([$userId]);if((int)$count->fetchColumn()>=$limits['playlists'])sf_json_response(['ok'=>false,'error'=>'playlist_limit_reached','limit'=>$limits['playlists']],409);$stmt=$pdo->prepare("INSERT INTO playlists (user_id,title,slug,description,visibility) VALUES (?,?,?,?,'private')");$stmt->execute([$userId,$title,sf_playlist_slug($title),$description]);sf_json_response(['ok'=>true,'playlist_id'=>(int)$pdo->lastInsertId(),'title'=>$title]);}if($action==='add_song'){$playlistId=sf_int_from_request($data,'playlist_id');$songId=sf_int_from_request($data,'song_id');if($songId<=0)sf_json_response(['ok'=>false,'error'=>'song_id_required'],422);$song=sf_media_song_record($songId);if(!$song)sf_json_response(['ok'=>false,'error'=>'song_not_found'],404);if(!sf_media_user_can_access('song',$song,'full'))sf_json_response(['ok'=>false,'error'=>'song_access_denied'],403);if($playlistId<=0)$playlistId=sf_member_default_playlist($pdo,(int)$userId,$limits['playlists']);$owner=$pdo->prepare('SELECT id FROM playlists WHERE id=? AND user_id=? LIMIT 1');$owner->execute([$playlistId,$userId]);if(!$owner->fetch())sf_json_response(['ok'=>false,'error'=>'playlist_not_found'],404);$count=$pdo->prepare('SELECT COUNT(*) FROM playlist_songs WHERE playlist_id=?');$count->execute([$playlistId]);if((int)$count->fetchColumn()>=$limits['tracks'])sf_json_response(['ok'=>false,'error'=>'playlist_track_limit_reached','limit'=>$limits['tracks']],409);$order=$pdo->prepare('SELECT COALESCE(MAX(sort_order),0)+1 FROM playlist_songs WHERE playlist_id=?');$order->execute([$playlistId]);$stmt=$pdo->prepare('INSERT IGNORE INTO playlist_songs (playlist_id,song_id,sort_order) VALUES (?,?,?)');$stmt->execute([$playlistId,$songId,(int)$order->fetchColumn()]);sf_json_response(['ok'=>true,'playlist_id'=>$playlistId,'song_id'=>$songId]);}if($action==='remove_song'){$playlistId=sf_int_from_request($data,'playlist_id');$songId=sf_int_from_request($data,'song_id');if($playlistId<=0||$songId<=0)sf_json_response(['ok'=>false,'error'=>'playlist_id_and_song_id_required'],422);$stmt=$pdo->prepare('DELETE ps FROM playlist_songs ps INNER JOIN playlists p ON p.id=ps.playlist_id WHERE p.user_id=? AND ps.playlist_id=? AND ps.song_id=?');$stmt->execute([$userId,$playlistId,$songId]);sf_json_response(['ok'=>true,'removed'=>$stmt->rowCount()>0]);}sf_json_response(['ok'=>false,'error'=>'unknown_action'],400);}catch(RuntimeException$e){sf_json_response(['ok'=>false,'error'=>$e->getMessage()],409);}catch(Throwable$e){error_log('Playlist API failed: '.$e->getMessage());sf_json_response(['ok'=>false,'error'=>'playlist_action_failed'],500);}
